<body>
  <main class="app">
    <section class="panel hud" aria-label="Game information">
      <div class="title-block">
        <h1>Snake</h1>
        <p class="subtitle">Use the arrow keys to move. Eat food, avoid walls and yourself.</p>
      </div>
      <div class="stats">
        <div class="stat">
          <span class="stat-label">Score</span>
          <span class="stat-value" id="score">0</span>
        </div>
        <div class="stat">
          <span class="stat-label">Best</span>
          <span class="stat-value" id="best">0</span>
        </div>
      </div>
    </section>

    <section class="panel game-shell">
      <canvas id="board" width="600" height="600" aria-label="Snake game board"></canvas>
      <div class="overlay visible" id="overlay" aria-live="polite">
        <div class="overlay-card">
          <h2 id="overlay-title">Ready?</h2>
          <p id="overlay-text">Press any arrow key to start the round.</p>
          <button id="restart-button" type="button">Start Game</button>
        </div>
      </div>
    </section>

    <section class="panel footer" aria-label="Controls">
      <span><strong>Controls:</strong> Arrow keys</span>
      <span><strong>Restart:</strong> Button, Enter, or Space</span>
    </section>
  </main>

  <script>
    const canvas = document.getElementById("board");
    const ctx = canvas.getContext("2d");
    const scoreEl = document.getElementById("score");
    const bestEl = document.getElementById("best");
    const overlay = document.getElementById("overlay");
    const overlayTitle = document.getElementById("overlay-title");
    const overlayText = document.getElementById("overlay-text");
    const restartButton = document.getElementById("restart-button");

    const gridSize = 20;
    const cellSize = canvas.width / gridSize;
    const moveInterval = 120;
    const storageKey = "snake-best-score";
    const directionMap = {
      ArrowUp: { x: 0, y: -1 },
      ArrowDown: { x: 0, y: 1 },
      ArrowLeft: { x: -1, y: 0 },
      ArrowRight: { x: 1, y: 0 }
    };

    let snake;
    let direction;
    let queuedDirection;
    let food;
    let score;
    let bestScore = Number.parseInt(localStorage.getItem(storageKey) || "0", 10) || 0;
    let lastTick = 0;
    let running = false;
    let hasStarted = false;
    let gameOver = false;

    bestEl.textContent = String(bestScore);

    function randomEmptyCell() {
      const occupied = new Set(snake.map((segment) => `${segment.x},${segment.y}`));
      const openCells = [];

      for (let y = 0; y < gridSize; y += 1) {
        for (let x = 0; x < gridSize; x += 1) {
          const key = `${x},${y}`;
          if (!occupied.has(key)) {
            openCells.push({ x, y });
          }
        }
      }

      return openCells[Math.floor(Math.random() * openCells.length)];
    }

    function syncScore() {
      scoreEl.textContent = String(score);
      if (score > bestScore) {
        bestScore = score;
        bestEl.textContent = String(bestScore);
        localStorage.setItem(storageKey, String(bestScore));
      }
    }

    function showOverlay(title, text, buttonText) {
      overlayTitle.textContent = title;
      overlayText.textContent = text;
      restartButton.textContent = buttonText;
      overlay.classList.add("visible");
    }

    function hideOverlay() {
      overlay.classList.remove("visible");
    }

    function resetGame() {
      snake = [
        { x: 10, y: 10 },
        { x: 9, y: 10 },
        { x: 8, y: 10 }
      ];
      direction = { x: 1, y: 0 };
      queuedDirection = { x: 1, y: 0 };
      food = randomEmptyCell();
      score = 0;
      running = false;
      hasStarted = false;
      gameOver = false;
      lastTick = 0;
      syncScore();
      showOverlay("Ready?", "Press any arrow key to start the round.", "Start Game");
      draw();
    }

    function isOpposite(next, current) {
      return next.x === -current.x && next.y === -current.y;
    }

    function startGame() {
      if (gameOver) {
        resetGame();
      }
      running = true;
      hasStarted = true;
      hideOverlay();
    }

    function endGame() {
      running = false;
      gameOver = true;
      showOverlay("Game Over", `Final score: ${score}. Press Enter, Space, or the button to play again.`, "Play Again");
    }

    function update() {
      direction = queuedDirection;

      const head = snake[0];
      const nextHead = {
        x: head.x + direction.x,
        y: head.y + direction.y
      };

      const hitsWall =
        nextHead.x < 0 ||
        nextHead.x >= gridSize ||
        nextHead.y < 0 ||
        nextHead.y >= gridSize;

      const hitsSelf = snake.some((segment) => segment.x === nextHead.x && segment.y === nextHead.y);

      if (hitsWall || hitsSelf) {
        endGame();
        return;
      }

      snake.unshift(nextHead);

      if (nextHead.x === food.x && nextHead.y === food.y) {
        score += 1;
        syncScore();
        food = randomEmptyCell();
      } else {
        snake.pop();
      }
    }

    function drawGrid() {
      ctx.strokeStyle = "rgba(255, 255, 255, 0.04)";
      ctx.lineWidth = 1;

      for (let i = 1; i < gridSize; i += 1) {
        const offset = i * cellSize;
        ctx.beginPath();
        ctx.moveTo(offset, 0);
        ctx.lineTo(offset, canvas.height);
        ctx.stroke();
        ctx.beginPath();
        ctx.moveTo(0, offset);
        ctx.lineTo(canvas.width, offset);
        ctx.stroke();
      }
    }

    function drawFood() {
      const x = food.x * cellSize;
      const y = food.y * cellSize;
      const padding = cellSize * 0.18;

      ctx.fillStyle = "#ff846c";
      ctx.beginPath();
      ctx.roundRect(x + padding, y + padding, cellSize - padding * 2, cellSize - padding * 2, 8);
      ctx.fill();
    }

    function drawSnake() {
      snake.forEach((segment, index) => {
        const x = segment.x * cellSize;
        const y = segment.y * cellSize;
        const padding = index === 0 ? cellSize * 0.1 : cellSize * 0.14;

        ctx.fillStyle = index === 0 ? "#57e389" : "#2f8f54";
        ctx.beginPath();
        ctx.roundRect(x + padding, y + padding, cellSize - padding * 2, cellSize - padding * 2, 8);
        ctx.fill();
      });
    }

    function draw() {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      ctx.fillStyle = getComputedStyle(document.documentElement).getPropertyValue("--grid");
      ctx.fillRect(0, 0, canvas.width, canvas.height);
      drawGrid();
      drawFood();
      drawSnake();
    }

    function loop(timestamp) {
      if (running) {
        if (!lastTick) {
          lastTick = timestamp;
        }

        if (timestamp - lastTick >= moveInterval) {
          update();
          draw();
          lastTick = timestamp;
        }
      } else {
        lastTick = timestamp;
      }

      requestAnimationFrame(loop);
    }

    function handleDirectionInput(key) {
      const nextDirection = directionMap[key];
      if (!nextDirection) {
        return false;
      }

      if (!hasStarted || gameOver) {
        resetGame();
        running = true;
        hasStarted = true;
        hideOverlay();
      }

      if (!isOpposite(nextDirection, direction)) {
        queuedDirection = nextDirection;
      }

      return true;
    }

    document.addEventListener("keydown", (event) => {
      if (handleDirectionInput(event.key)) {
        event.preventDefault();
        return;
      }

      if ((event.key === "Enter" || event.key === " ") && overlay.classList.contains("visible")) {
        event.preventDefault();
        resetGame();
      }
    });

    restartButton.addEventListener("click", () => {
      resetGame();
    });

    resetGame();
    requestAnimationFrame(loop);
  </script>
</body>
</html>
